func extractSingleQuotedStrings(s string) []string {
	var (
		inQuote	bool
		lo	int
		hi	int
	)

	var words []string

	for i, r := range s {
		switch {
		case r == '\'':
			if !inQuote {
				inQuote = true
				lo = i + 1
			} else {
				inQuote = false
				hi = i
				words = append(words, strings.Fields(s[lo:hi])...)
			}
		}
	}

	return words
}
